     1→/**
     2→ * Jiranimo content script.
     3→ * Runs on Jira sprint board pages.
     4→ * Detects cards with the trigger label (via Jira API) and injects "Implement" badges.
     5→ * Polls the local server for task status updates.
     6→ */
     7→
     8→// @ts-check
     9→/* global chrome, BoardConfig */
    10→
    11→(function () {
    12→  'use strict';
    13→
    14→  const LOG_PREFIX = '[Jiranimo]';
    15→  const log = (...args) => console.log(LOG_PREFIX, ...args);
    16→  const warn = (...args) => console.warn(LOG_PREFIX, ...args);
    17→
    18→  const BADGE_ATTR = 'data-jiranimo';
    19→  const SCAN_DEBOUNCE = 500;
    20→  const WS_RECONNECT_DELAY = 3000;
    21→  const SPARKLES_SVG = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor"><path fill-rule="evenodd" d="M9 4.5a.75.75 0 01.721.544l.813 2.846a3.75 3.75 0 002.576 2.576l2.846.813a.75.75 0 010 1.442l-2.846.813a3.75 3.75 0 00-2.576 2.576l-.813 2.846a.75.75 0 01-1.442 0l-.813-2.846a3.75 3.75 0 00-2.576-2.576l-2.846-.813a.75.75 0 010-1.442l2.846-.813A3.75 3.75 0 007.466 7.89l.813-2.846A.75.75 0 019 4.5zM18 1.5a.75.75 0 01.728.568l.258 1.036c.236.94.97 1.674 1.91 1.91l1.036.258a.75.75 0 010 1.456l-1.036.258c-.94.236-1.674.97-1.91 1.91l-.258 1.036a.75.75 0 01-1.456 0l-.258-1.036a2.625 2.625 0 00-1.91-1.91l-1.036-.258a.75.75 0 010-1.456l1.036-.258a2.625 2.625 0 001.91-1.91l.258-1.036A.75.75 0 0118 1.5zM16.5 15a.75.75 0 01.712.513l.394 1.183c.15.447.5.799.948.948l1.183.395a.75.75 0 010 1.422l-1.183.395c-.447.15-.799.5-.948.948l-.395 1.183a.75.75 0 01-1.422 0l-.395-1.183a1.5 1.5 0 00-.948-.948l-1.183-.395a.75.75 0 010-1.422l1.183-.395c.447-.15.799-.5.948-.948l.395-1.183A.75.75 0 0116.5 15z" clip-rule="evenodd"/></svg>';
    22→
    23→  /** @type {Record<string, string>} taskKey -> status */
    24→  let taskStatuses = {};
    25→  /** @type {Record<string, string>} taskKey -> prUrl */
    26→  let taskPrUrls = {};
    27→
    28→  // Restore task statuses from sessionStorage so animations survive page reloads
    29→  try {
    30→    const saved = JSON.parse(sessionStorage.getItem('jiranimo-statuses') || '{}');
    31→    const savedUrls = JSON.parse(sessionStorage.getItem('jiranimo-prurls') || '{}');
    32→    Object.assign(taskStatuses, saved);
    33→    Object.assign(taskPrUrls, savedUrls);
    34→    log('Restored', Object.keys(saved).length, 'task statuses from sessionStorage');
    35→  } catch { /* ignore */ }
    36→
    37→  function persistStatuses() {
    38→    try {
    39→      sessionStorage.setItem('jiranimo-statuses', JSON.stringify(taskStatuses));
    40→      sessionStorage.setItem('jiranimo-prurls', JSON.stringify(taskPrUrls));
    41→    } catch { /* ignore */ }
    42→  }
    43→
    44→  /** @type {string} */
    45→  let serverUrl = 'http://localhost:3456';
    46→  /** @type {object|null} */
    47→  let boardConfig = null;
    48→  /** @type {number|null} */
    49→  let scanTimer = null;
    50→  /** @type {string|null} */
    51→  let currentBoardId = null;
    52→  /** @type {Array<{key: string, summary: string, labels: string[]}>|null} */
    53→  let cachedSprintIssues = null;
    54→
    55→  async function init() {
    56→    log('Content script loaded on', location.href);
    57→
    58→    const settings = await chrome.storage.local.get(['serverUrl']);
    59→    serverUrl = settings.serverUrl || 'http://localhost:3456';
    60→    log('Config — serverUrl:', serverUrl);
    61→
    62→    currentBoardId = getBoardId();
    63→    if (!currentBoardId) {
    64→      warn('Could not extract board ID from URL');
    65→      return;
    66→    }
    67→    log('Board ID:', currentBoardId);
    68→
    69→    const stored = await chrome.storage.local.get([`boardConfig_${currentBoardId}`]);
    70→    boardConfig = stored[`boardConfig_${currentBoardId}`] || null;
    71→
    72→    if (!boardConfig) {
    73→      log('No board config found — showing setup modal');
    74→      BoardConfig.show(currentBoardId, (config) => {
    75→        boardConfig = config;
    76→        startScanning();
    77→      });
    78→    } else {
    79→      log('Board config loaded:', JSON.stringify(boardConfig));
    80→      startScanning();
    81→    }
    82→  }
    83→
    84→  function getBoardId() {
    85→    const match = location.pathname.match(/\/boards\/(\d+)/);
    86→    return match ? match[1] : null;
    87→  }
    88→
    89→  function startScanning() {
    90→    log('Starting card scanner');
    91→    setTimeout(() => scanCards(), 1000);
    92→    observeCardChanges();
    93→    connectWebSocket();
    94→  }
    95→
    96→  function debouncedScan() {
    97→    if (scanTimer) clearTimeout(scanTimer);
    98→    scanTimer = setTimeout(() => scanCards(), SCAN_DEBOUNCE);
    99→  }
   100→
   101→  async function scanCards() {
   102→    if (!cachedSprintIssues) {
   103→      cachedSprintIssues = await fetchSprintIssues();
   104→    }
   105→    if (!cachedSprintIssues) {
   106→      log('No sprint issues found');
   107→      return;
   108→    }
   109→    log(`Scanning ${cachedSprintIssues.length} sprint issues`);
   110→
   111→    const triggerLabel = boardConfig?.triggerLabel;
   112→    let injected = 0;
   113→    for (const issue of cachedSprintIssues) {
   114→      const key = issue.key;
   115→      if (triggerLabel && !issue.labels.includes(triggerLabel)) continue;
   116→      if (document.querySelector(`[${BADGE_ATTR}="${key}"]`)) continue;
   117→      const titleEl = findIssueTitleElement(key);
   118→      if (!titleEl) continue;
   119→      injectBadge(titleEl, key);
   120→      injected++;
   121→    }
   122→    log(`Injected ${injected} badges`);
   123→  }
   124→
   125→  async function fetchSprintIssues() {
   126→    try {
   127→      const sprintRes = await fetch(
   128→        `${location.origin}/rest/agile/1.0/board/${currentBoardId}/sprint?state=active`,
   129→        { credentials: 'include' }
   130→      );
   131→      if (!sprintRes.ok) { warn('Failed to fetch active sprint:', sprintRes.status); return null; }
   132→      const sprintData = await sprintRes.json();
   133→      const sprint = sprintData.values?.[0];
   134→      if (!sprint) { warn('No active sprint found'); return null; }
   135→      log('Active sprint:', sprint.name);
   136→
   137→      const issueRes = await fetch(
   138→        `${location.origin}/rest/agile/1.0/sprint/${sprint.id}/issue?fields=summary,labels&maxResults=200`,
   139→        { credentials: 'include' }
   140→      );
   141→      if (!issueRes.ok) { warn('Failed to fetch sprint issues:', issueRes.status); return null; }
   142→      const issueData = await issueRes.json();
   143→      return (issueData.issues || []).map(i => ({ key: i.key, summary: i.fields.summary, labels: i.fields.labels || [] }));
   144→    } catch (err) {
   145→      warn('fetchSprintIssues error:', err);
   146→      return null;
   147→    }
   148→  }
   149→
   150→  function findIssueTitleElement(issueKey) {
   151→    for (const el of document.querySelectorAll('div, a, span')) {
   152→      if (el.childElementCount === 0 && el.textContent.trim() === issueKey) {
   153→        log(`findIssueTitleElement: found key element for ${issueKey}`);
   154→        return el;
   155→      }
   156→    }
   157→    log(`findIssueTitleElement: no element found for ${issueKey}`);
   158→    return null;
   159→  }
   160→
   161→  /**
   162→   * Fetch labels for multiple issues via Jira REST API using JQL search.
   163→   */
   164→
   165→  /**
   166→   * Fetch full issue details from Jira REST API (content script has session cookies).
   167→   * Returns data ready to POST to the server.
   168→   */
   169→  async function fetchIssueDetails(issueKey) {
   170→    try {
   171→      const fields = 'summary,description,priority,issuetype,labels,comment,status,subtasks,parent,issuelinks,assignee,reporter,components,attachment';
   172→      const url = `${location.origin}/rest/api/3/issue/${issueKey}?fields=${fields}&expand=renderedFields`;
   173→      log('Fetching issue details:', issueKey);
   174→      const res = await fetch(url, { credentials: 'include' });
   175→      if (!res.ok) {
   176→        warn('Issue fetch failed:', res.status);
   177→        return null;
   178→      }
   179→      const issue = await res.json();
   180→      const f = issue.fields;
   181→
   182→      // Convert ADF description to plain text
   183→      let description = '';
   184→      if (f.description) {
   185→        description = extractTextFromAdf(f.description);
   186→      }
   187→      if (!description && issue.renderedFields?.description) {
   188→        description = issue.renderedFields.description.replace(/<[^>]+>/g, '');
   189→      }
   190→
   191→      return {
   192→        key: issueKey,
   193→        summary: f.summary || issueKey,
   194→        description: description || f.summary || '',
   195→        priority: f.priority?.name || 'Medium',
   196→        issueType: f.issuetype?.name || 'Task',
   197→        labels: f.labels || [],
   198→        comments: (f.comment?.comments || []).slice(-10).map(c => ({
   199→          author: c.author?.displayName || 'Unknown',
   200→          body: extractTextFromAdf(c.body),
   201→          created: c.created,
   202→        })),
   203→        subtasks: (f.subtasks || []).map(s => ({
   204→          key: s.key,
   205→          summary: s.fields?.summary || '',
   206→          status: s.fields?.status?.name || '',
   207→        })),
   208→        linkedIssues: (f.issuelinks || []).map(l => {
   209→          const linked = l.outwardIssue || l.inwardIssue;
   210→          return { type: l.type?.outward || 'related', key: linked?.key || '', summary: linked?.fields?.summary || '', status: linked?.fields?.status?.name || '' };
   211→        }).filter(l => l.key),
   212→        attachments: (f.attachment || []).map(a => ({ filename: a.filename, mimeType: a.mimeType, url: a.content })),
   213→        assignee: f.assignee?.displayName || '',
   214→        reporter: f.reporter?.displayName || '',
   215→        components: (f.components || []).map(c => c.name),
   216→        parentKey: f.parent?.key || '',
   217→        jiraUrl: `${location.origin}/browse/${issueKey}`,
   218→        projectKey: issueKey.split('-')[0],
   219→      };
   220→    } catch (err) {
   221→      warn('fetchIssueDetails error:', err);
   222→      return null;
   223→    }
   224→  }
   225→
   226→  /**
   227→   * Transition a Jira issue by name. Fetches available transitions,
   228→   * finds the matching one, and executes it. Done directly from the
   229→   * content script so session cookies are available (works in incognito).
   230→   */
   231→  async function transitionIssue(issueKey, transitionName) {
   232→    try {
   233→      log(`Transitioning ${issueKey} to "${transitionName}"`);
   234→      const transRes = await fetch(`${location.origin}/rest/api/3/issue/${issueKey}/transitions`, { credentials: 'include' });
   235→      if (!transRes.ok) { warn('Failed to get transitions:', transRes.status); return; }
   236→      const data = await transRes.json();
   237→      const match = (data.transitions || []).find(t => t.name.toLowerCase() === transitionName.toLowerCase());
   238→      if (!match) { warn(`Transition "${transitionName}" not found. Available:`, (data.transitions || []).map(t => t.name)); return; }
   239→      const execRes = await fetch(`${location.origin}/rest/api/3/issue/${issueKey}/transitions`, {
   240→        method: 'POST',
   241→        headers: { 'Content-Type': 'application/json' },
   242→        credentials: 'include',
   243→        body: JSON.stringify({ transition: { id: match.id } }),
   244→      });
   245→      if (execRes.ok) {
   246→        log(`Transitioned ${issueKey} to "${match.name}" — refreshing board`);
   247→        // Brief delay for Jira to process, then reload so the card appears in the new column
   248→        setTimeout(() => location.reload(), 500);
   249→      } else {
   250→        warn(`Transition failed: ${execRes.status}`);
   251→      }
   252→    } catch (err) { warn('transitionIssue error:', err); }
   253→  }
   254→
   255→  /**
   256→   * Post a comment on a Jira issue directly from the content script.
   257→   */
   258→  async function postJiraComment(issueKey, text) {
   259→    try {
   260→      await fetch(`${location.origin}/rest/api/3/issue/${issueKey}/comment`, {
   261→        method: 'POST',
   262→        headers: { 'Content-Type': 'application/json' },
   263→        credentials: 'include',
   264→        body: JSON.stringify({
   265→          body: { type: 'doc', version: 1, content: [{ type: 'paragraph', content: [{ type: 'text', text }] }] },
   266→        }),
   267→      });
   268→      log(`Comment posted on ${issueKey}`);
   269→    } catch (err) { warn('postJiraComment error:', err); }
   270→  }
   271→
   272→  /**
   273→   * Post a concise completion comment on the Jira issue.
   274→   * Includes PR link if available, and Claude's result summary if useful.
   275→   */
   276→  async function postCompletionComment(task) {
   277→    const parts = [];
   278→
   279→    if (task.prUrl) {
   280→      parts.push(`Draft PR: ${task.prUrl}`);
   281→    }
   282→
   283→    // Include Claude's summary if it's substantive (not just "done")
   284→    if (task.claudeResultText) {
   285→      const text = task.claudeResultText.trim();
   286→      // Only include if it's more than a trivial response
   287→      if (text.length > 10 && text.length < 2000) {
   288→        parts.push(text);
   289→      }
   290→    }
   291→
   292→    if (task.claudeCostUsd) {
   293→      parts.push(`Cost: $${task.claudeCostUsd.toFixed(2)}`);
   294→    }
   295→
   296→    if (task.screenshotFailed) {
   297→      const reason = task.screenshotFailReason ? ` Reason: ${task.screenshotFailReason}` : '';
   298→      parts.push(
   299→        `⚠️ I wasn't able to take a screenshot of the feature.${reason}\n\n` +
   300→        `To add one: reply to this comment with instructions on how to screenshot this feature ` +
   301→        `(e.g. which URL to visit, how to start the dev server, what to click), ` +
   302→        `then click the AI button on this card again.`
   303→      );
   304→    }
   305→
   306→    if (parts.length === 0) {
   307→      parts.push('Done');
   308→    }
   309→
   310→    parts.push('\n— Jiranimo + Claude Code');
   311→
   312→    await postJiraComment(task.key, parts.join('\n\n'));
   313→  }
   314→
   315→  /** Simple recursive ADF text extractor */
   316→  function extractTextFromAdf(node) {
   317→    if (!node) return '';
   318→    if (node.type === 'text') return node.text || '';
   319→    if (node.type === 'hardBreak') return '\n';
   320→    if (Array.isArray(node.content)) return node.content.map(extractTextFromAdf).join('');
   321→    if (node.type === 'doc' && Array.isArray(node.content)) return node.content.map(extractTextFromAdf).join('\n\n');
   322→    return '';
   323→  }
   324→
   325→  function injectBadge(titleEl, issueKey) {
   326→    const icon = document.createElement('span');
   327→    icon.setAttribute(BADGE_ATTR, issueKey);
   328→    icon.className = 'jiranimo-icon idle';
   329→    icon.title = 'Implement with AI';
   330→    icon.innerHTML = SPARKLES_SVG;
   331→
   332→    const currentStatus = taskStatuses[issueKey];
   333→    if (currentStatus) {
   334→      updateBadgeState(icon, issueKey, currentStatus);
   335→    }
   336→
   337→    icon.addEventListener('click', (e) => {
   338→      e.preventDefault();
   339→      e.stopPropagation();
   340→      handleBadgeClick(icon, issueKey);
   341→    });
   342→
   343→    const wrapper = document.createElement('span');
   344→    wrapper.style.cssText = 'display: inline-flex; align-items: center; flex-direction: row; direction: ltr;';
   345→    titleEl.parentNode.insertBefore(wrapper, titleEl);
   346→    wrapper.appendChild(titleEl);
   347→    wrapper.appendChild(icon);
   348→    log(`Icon injected for ${issueKey}`);
   349→  }
   350→
   351→  function setBadgeState(icon, issueKey, status, titleOverride) {
   352→    updateBadgeState(icon, issueKey, status);
   353→    if (titleOverride) icon.title = titleOverride;
   354→  }
   355→
   356→  /** Proxy server API calls through the background service worker to avoid
   357→   *  Chrome's Private Network Access block (atlassian.net → localhost).
   358→   * @param {string} path
   359→   * @param {string} [method]
   360→   * @param {unknown} [body]
   361→   */
   362→  function serverFetch(path, method, body) {
   363→    return new Promise((resolve, reject) => {
   364→      // @ts-ignore — chrome global is declared at top of file
   365→      chrome.runtime.sendMessage(
   366→        { type: 'server-fetch', path, method: method || 'GET', body },
   367→        // @ts-ignore
   368→        (response) => {
   369→          // @ts-ignore
   370→          if (chrome.runtime.lastError) { reject(new Error(chrome.runtime.lastError.message)); return; }
   371→          if (!response) { reject(new Error('No response from background')); return; }
   372→          resolve(response);
   373→        }
   374→      );
   375→    });
   376→  }
   377→
   378→  async function handleBadgeClick(icon, issueKey) {
   379→    const status = taskStatuses[issueKey];
   380→
   381→    if (status === 'failed') {
   382→      setBadgeState(icon, issueKey, 'in-progress', 'Retrying...');
   383→      try {
   384→        await serverFetch(`/api/tasks/${issueKey}/retry`, 'POST');
   385→      } catch (err) {
   386→        setBadgeState(icon, issueKey, 'failed', 'Error — click to retry');
   387→      }
   388→      return;
   389→    }
   390→
   391→    if (status === 'queued' || status === 'in-progress') return;
   392→
   393→    if (status === 'completed' && taskPrUrls[issueKey]) {
   394→      window.open(taskPrUrls[issueKey], '_blank');
   395→      return;
   396→    }
   397→
   398→    setBadgeState(icon, issueKey, 'in-progress', 'Sending to server...');
   399→
   400→    try {
   401→      const issueData = await fetchIssueDetails(issueKey);
   402→      if (!issueData) {
   403→        setBadgeState(icon, issueKey, 'failed', 'Failed to fetch issue — click to retry');
   404→        return;
   405→      }
   406→
   407→      /** @type {any} */
   408→      const result = await serverFetch('/api/tasks', 'POST', issueData);
   409→
   410→      if (result.ok) {
   411→        updateBadgeState(icon, issueKey, 'queued');
   412→        taskStatuses[issueKey] = 'queued';
   413→        persistStatuses();
   414→
   415→        if (boardConfig?.transitions?.inProgress) {
   416→          transitionIssue(issueKey, boardConfig.transitions.inProgress.name);
   417→        }
   418→      } else {
   419→        setBadgeState(icon, issueKey, 'failed', (result.data?.error || `Error ${result.status}`) + ' — click to retry');
   420→      }
   421→    } catch (err) {
   422→      warn('Implement failed (is the server running?):', err);
   423→      setBadgeState(icon, issueKey, 'failed', 'Server offline — click to retry');
   424→    }
   425→  }
   426→
   427→  function updateBadgeState(icon, issueKey, status) {
   428→    const label = icon.querySelector('.jiranimo-label');
   429→    switch (status) {
   430→      case 'queued':
   431→        icon.className = 'jiranimo-icon queued';
   432→        icon.title = 'Queued';
   433→        if (label) label.textContent = 'Queued';
   434→        break;
   435→      case 'in-progress':
   436→        icon.className = 'jiranimo-icon in-progress';
   437→        icon.title = 'Running...';
   438→        if (label) label.textContent = 'Running...';
   439→        break;
   440→      case 'completed':
   441→        icon.className = 'jiranimo-icon completed';
   442→        icon.title = 'PR ready — click to open';
   443→        if (label) label.textContent = 'Done';
   444→        break;
   445→      case 'failed':
   446→        icon.className = 'jiranimo-icon failed';
   447→        icon.title = 'Failed — click to retry';
   448→        if (label) label.textContent = 'Failed';
   449→        break;
   450→      default:
   451→        icon.className = 'jiranimo-icon idle';
   452→        icon.title = 'Implement with AI';
   453→        if (label) label.textContent = 'Implement';
   454→    }
   455→  }
   456→
   457→  function observeCardChanges() {
   458→    const observer = new MutationObserver(() => {
   459→      debouncedScan();
   460→    });
   461→    observer.observe(document.body, { childList: true, subtree: true });
   462→    log('MutationObserver attached');
   463→  }
   464→
   465→  /** @type {WebSocket|null} */
   466→  let ws = null;
   467→
   468→  async function syncTaskStatuses() {
   469→    try {
   470→      /** @type {any} */
   471→      const syncResult = await serverFetch('/api/tasks');
   472→      if (!syncResult.ok) return;
   473→      const tasks = syncResult.data;
   474→
   475→      // Collect completed/failed task keys to check against Jira
   476→      const toCheck = tasks.filter(t => t.status === 'completed' || t.status === 'failed');
   477→
   478→      // Check if any completed/failed tasks were moved back to To Do in Jira
   479→      const resetKeys = new Set();
   480→      if (toCheck.length > 0) {
   481→        const keys = toCheck.map(t => t.key);
   482→        try {
   483→          const jql = `key in (${keys.join(',')})`;
   484→          const jiraRes = await fetch(`${location.origin}/rest/api/3/search/jql`, {
   485→            method: 'POST',
   486→            headers: { 'Content-Type': 'application/json' },
   487→            credentials: 'include',
   488→            body: JSON.stringify({ jql, fields: ['status'], maxResults: 50 }),
   489→          });
   490→          if (jiraRes.ok) {
   491→            const jiraData = await jiraRes.json();
   492→            for (const issue of jiraData.issues || []) {
   493→              const jiraStatus = issue.fields?.status?.name?.toLowerCase() || '';
   494→              if (jiraStatus.includes('to do') || jiraStatus.includes('todo')) {
   495→                log(`${issue.key} moved back to To Do in Jira — resetting`);
   496→                resetKeys.add(issue.key);
   497→                delete taskStatuses[issue.key];
   498→                delete taskPrUrls[issue.key];
   499→                serverFetch(`/api/tasks/${issue.key}`, 'DELETE').catch(() => {});
   500→              }
   501→            }
   502→          }
   503→        } catch {
   504→          // Jira API call failed — skip the check
   505→        }
   506→      }
   507→
   508→      for (const task of tasks) {
   509→        if (resetKeys.has(task.key)) continue;
   510→        taskStatuses[task.key] = task.status;
   511→        if (task.prUrl) taskPrUrls[task.key] = task.prUrl;
   512→        const badge = document.querySelector(`[${BADGE_ATTR}="${task.key}"]`);
   513→        if (badge) {
   514→          updateBadgeState(badge, task.key, task.status);
   515→        }
   516→      }
   517→      persistStatuses();
   518→      log('Synced', tasks.length, 'task statuses from server');
   519→    } catch {
   520→      // Server not running
   521→    }
   522→  }
   523→
   524→  function connectWebSocket() {
   525→    const wsUrl = serverUrl.replace(/^http/, 'ws') + '/ws';
   526→    log('Connecting WebSocket:', wsUrl);
   527→
   528→    try {
   529→      ws = new WebSocket(wsUrl);
   530→    } catch {
   531→      log('WebSocket connection failed, retrying in', WS_RECONNECT_DELAY, 'ms');
   532→      setTimeout(connectWebSocket, WS_RECONNECT_DELAY);
   533→      return;
   534→    }
   535→
   536→    ws.onopen = async () => {
   537→      log('WebSocket connected');
   538→      // Restore task statuses from server (in case page was refreshed)
   539→      await syncTaskStatuses();
   540→    };
   541→
   542→    ws.onmessage = (event) => {
   543→      try {
   544→        const msg = JSON.parse(event.data);
   545→        handleServerMessage(msg);
   546→      } catch {
   547→        // ignore malformed messages
   548→      }
   549→    };
   550→
   551→    ws.onclose = () => {
   552→      log('WebSocket disconnected, reconnecting...');
   553→      ws = null;
   554→      setTimeout(connectWebSocket, WS_RECONNECT_DELAY);
   555→    };
   556→
   557→    ws.onerror = () => {
   558→      // onclose will fire after this, triggering reconnect
   559→    };
   560→  }
   561→
   562→  function handleServerMessage(msg) {
   563→    if (msg.type === 'task-status-changed' || msg.type === 'task-created' || msg.type === 'task-completed') {
   564→      const task = msg.task;
   565→      if (!task?.key) return;
   566→
   567→      const oldStatus = taskStatuses[task.key];
   568→      taskStatuses[task.key] = task.status;
   569→      if (task.prUrl) taskPrUrls[task.key] = task.prUrl;
   570→      persistStatuses();
   571→
   572→      // Update badge
   573→      const badge = document.querySelector(`[${BADGE_ATTR}="${task.key}"]`);
   574→      if (badge) {
   575→        updateBadgeState(badge, task.key, task.status);
   576→      }
   577→
   578→      // Update Jira when task completes: transition + comment
   579→      if (task.status === 'completed' && oldStatus !== 'completed') {
   580→        if (boardConfig?.transitions?.inReview) {
   581→          transitionIssue(task.key, boardConfig.transitions.inReview.name);
   582→        }
   583→        // Plan tasks: comment is posted via task-plan-ready (after server reads the plan file)
   584→        if (task.taskMode !== 'plan') {
   585→          postCompletionComment(task);
   586→        }
   587→      }
   588→
   589→      log(`Task ${task.key}: ${oldStatus || 'new'} → ${task.status}`);
   590→    }
   591→
   592→    // Server tells us to update Jira status — only for in-progress (completed is handled by task-status-changed)
   593→    if (msg.type === 'update-jira-status' && msg.issueKey && msg.pipelineStatus) {
   594→      if (msg.pipelineStatus === 'in-progress' && boardConfig?.transitions?.inProgress) {
   595→        transitionIssue(msg.issueKey, boardConfig.transitions.inProgress.name);
   596→      }
   597→    }
   598→
   599→    if (msg.type === 'task-plan-ready' && msg.taskKey && msg.planContent) {
   600→      postJiraComment(msg.taskKey, msg.planContent);
   601→    }
   602→  }
   603→
   604→  init().catch(err => warn('Init failed:', err));
   605→})();
   606→

