     1→import { Router, type Request, type Response } from 'express';
     2→import { readFileSync } from 'node:fs';
     3→import type { PipelineManager } from '../pipeline/manager.js';
     4→import type { StateStore } from '../state/store.js';
     5→
     6→export function createApiRouter(store: StateStore, pipeline: PipelineManager): Router {
     7→  const router = Router();
     8→
     9→  // POST /api/tasks — submit a new task
    10→  router.post('/tasks', (req: Request, res: Response) => {
    11→    const body = req.body;
    12→
    13→    if (!body.key || !body.summary || !body.priority || !body.issueType || !body.jiraUrl) {
    14→      res.status(400).json({ error: 'Missing required fields: key, summary, priority, issueType, jiraUrl' });
    15→      return;
    16→    }
    17→
    18→    try {
    19→      const task = pipeline.submitTask({
    20→        key: body.key,
    21→        summary: body.summary,
    22→        description: body.description || body.summary,
    23→        acceptanceCriteria: body.acceptanceCriteria,
    24→        priority: body.priority,
    25→        issueType: body.issueType,
    26→        labels: body.labels ?? [],
    27→        comments: body.comments ?? [],
    28→        subtasks: body.subtasks,
    29→        linkedIssues: body.linkedIssues,
    30→        attachments: body.attachments,
    31→        assignee: body.assignee,
    32→        reporter: body.reporter,
    33→        components: body.components,
    34→        parentKey: body.parentKey,
    35→        jiraUrl: body.jiraUrl,
    36→      });
    37→      res.status(201).json(task);
    38→    } catch (err) {
    39→      const message = (err as Error).message;
    40→      if (message.includes('already')) {
    41→        res.status(409).json({ error: message });
    42→      } else {
    43→        res.status(500).json({ error: message });
    44→      }
    45→    }
    46→  });
    47→
    48→  // GET /api/tasks — list all tasks
    49→  router.get('/tasks', (_req: Request, res: Response) => {
    50→    const tasks = store.getAllTasks();
    51→    res.json(tasks);
    52→  });
    53→
    54→  // GET /api/tasks/:key — get single task
    55→  router.get('/tasks/:key', (req: Request, res: Response) => {
    56→    const task = store.getTask(req.params.key);
    57→    if (!task) {
    58→      res.status(404).json({ error: `Task ${req.params.key} not found` });
    59→      return;
    60→    }
    61→    res.json(task);
    62→  });
    63→
    64→  // POST /api/tasks/:key/retry — retry a failed task
    65→  router.post('/tasks/:key/retry', (req: Request, res: Response) => {
    66→    try {
    67→      const task = pipeline.retryTask(req.params.key);
    68→      res.json(task);
    69→    } catch (err) {
    70→      const message = (err as Error).message;
    71→      if (message.includes('not found')) {
    72→        res.status(404).json({ error: message });
    73→      } else {
    74→        res.status(400).json({ error: message });
    75→      }
    76→    }
    77→  });
    78→
    79→  // DELETE /api/tasks/:key — remove a task (e.g. when moved back to To Do in Jira)
    80→  router.delete('/tasks/:key', (req: Request, res: Response) => {
    81→    const deleted = store.deleteTask(req.params.key);
    82→    if (deleted) {
    83→      res.json({ deleted: true });
    84→    } else {
    85→      res.status(404).json({ error: `Task ${req.params.key} not found` });
    86→    }
    87→  });
    88→
    89→  // GET /api/tasks/:key/logs — get task logs
    90→  router.get('/tasks/:key/logs', (req: Request, res: Response) => {
    91→    const task = store.getTask(req.params.key);
    92→    if (!task) {
    93→      res.status(404).json({ error: `Task ${req.params.key} not found` });
    94→      return;
    95→    }
    96→    if (!task.logPath) {
    97→      res.status(404).json({ error: 'No logs available for this task' });
    98→      return;
    99→    }
   100→    try {
   101→      const content = readFileSync(task.logPath, 'utf-8');
   102→      res.type('text/plain').send(content);
   103→    } catch {
   104→      res.status(404).json({ error: 'Log file not found' });
   105→    }
   106→  });
   107→
   108→  return router;
   109→}
   110→

