.jiranimo-icon {
  display: inline-flex;
  align-items: center;
  cursor: pointer;
  vertical-align: middle;
  margin-left: 4px;
  flex-shrink: 0;
  transition: color 0.15s, transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.jiranimo-icon:hover {
  transform: scale(1.4);
}

.jiranimo-icon svg {
  width: 1em;
  height: 1em;
  display: block;
}

.jiranimo-icon.idle { color: #0052cc; }
.jiranimo-icon.idle:hover { color: #0065ff; }

.jiranimo-icon.sending {
  color: #6b778c;
  cursor: wait;
  animation: jiranimo-spin 1s linear infinite;
}

.jiranimo-icon.queued {
  color: #ff991f;
  animation: jiranimo-pulse 1.5s ease-in-out infinite;
}

.jiranimo-icon.in-progress {
  color: #0052cc;
  animation: jiranimo-sparkle 1.2s ease-in-out infinite;
}

.jiranimo-icon.completed { color: #36b37e; }
.jiranimo-icon.completed:hover { color: #2d9f6f; }

.jiranimo-icon.failed { color: #de350b; }
.jiranimo-icon.failed:hover { color: #ff5630; }

@keyframes jiranimo-spin {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

